DarkRPUI.HUD.RegisterElement("alerts",{paint=function(ply) local sx,sy,sw=DarkRPUI.Layout.GetSafeRect(); if DarkRPUI.Util.DarkRPVar(ply,"wanted",false) then DarkRPUI.UI.MakeHUDCard(sx+sw/2-190,sy+10,380,56,"WANTED","Police are searching for you",DarkRPUI.Color("error")) end; if GetGlobalBool("DarkRP_LockDown") then DarkRPUI.UI.MakeHUDCard(sx+sw/2-190,sy+72,380,56,"LOCKDOWN","Return indoors",DarkRPUI.Color("warning")) end end})
